import{_ as o,o as r,c as a,ag as s,ah as e}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"插件","description":"","frontmatter":{},"headers":[],"relativePath":"settings/plugins.md","filePath":"settings/plugins.md"}'),n={name:"settings/plugins.md"};function l(d,t,i,g,c,h){return r(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="插件" tabindex="-1">插件 <a class="header-anchor" href="#插件" aria-label="Permalink to &quot;插件&quot;">​</a></h1><p><strong>入口：</strong> 侧边栏 → <strong>设置</strong> → <strong>插件</strong></p><p>插件（Plugin）是由社区或第三方开发者发布的功能扩展包，安装后可为 Claude CLI 或 Codex CLI 增加新的斜杠命令和工作流。安装的插件提供的命令会出现在 <code>/</code> 命令面板中，附带 <code>plugin</code> 来源标识。</p><p>本页通过 <strong>Claude | Codex</strong> 切换栏分别管理各 CLI 的插件。页面内容分为三个标签页：<strong>发现</strong>、<strong>已安装</strong>、<strong>市场</strong>。</p><p><img src="'+e+'" alt="插件设置页面，顶部 Claude/Codex 切换栏与三个标签，发现页展示可安装的插件卡片列表"></p><hr><h2 id="发现" tabindex="-1">发现 <a class="header-anchor" href="#发现" aria-label="Permalink to &quot;发现&quot;">​</a></h2><p><strong>发现</strong> 标签页列出当前已添加的市场中所有可安装的插件。</p><p>每张插件卡片显示名称、描述及来源市场标签。右侧提供安装操作：</p><ul><li><strong>Claude 模式</strong>：点击 <strong>安装</strong> 按钮后弹出作用域选择菜单，可选 <strong>用户</strong>、<strong>项目</strong> 或 <strong>本地</strong>（后两项需先关联工作区任务）</li><li><strong>Codex 模式</strong>：点击 <strong>安装</strong> 按钮直接以用户作用域安装，无作用域菜单</li></ul><p><strong>作用域说明：</strong></p><table tabindex="0"><thead><tr><th>作用域</th><th>生效范围</th></tr></thead><tbody><tr><td><strong>用户</strong></td><td>当前用户的所有工作区</td></tr><tr><td><strong>项目</strong></td><td>当前工作区所在项目（需关联工作区任务）</td></tr><tr><td><strong>本地</strong></td><td>仅限本地，不随项目同步（需关联工作区任务）</td></tr></tbody></table><p>若搜索栏输入关键词，结果会实时过滤插件名称和描述。</p><hr><h2 id="已安装" tabindex="-1">已安装 <a class="header-anchor" href="#已安装" aria-label="Permalink to &quot;已安装&quot;">​</a></h2><p><strong>已安装</strong> 标签页列出已安装的全部插件，显示名称、版本号及作用域标签。</p><p>每行右侧提供两个操作：</p><ul><li><strong>启用开关</strong> — 即时启用或禁用插件；禁用后该插件提供的命令在 <code>/</code> 面板中不再显示</li><li><strong>删除按钮</strong>（垃圾桶图标）— 删除插件并弹出确认对话框，确认后不可撤销</li></ul><div class="warning custom-block"><p class="custom-block-title">更新插件需先删除再重装</p><p>已安装列表中没有单独的&quot;升级&quot;按钮。若需更新插件版本，请先删除旧版本，再从 <strong>发现</strong> 标签页重新安装最新版本。删除操作通过对应 CLI 自身的插件管理命令完成，具体清理范围由 CLI 决定；如果你对该插件做过自定义配置，删除前请自行备份。</p></div><p>插件的命令在 <code>/</code> 命令面板中带有 <code>plugin</code> 来源标识，详见 <a href="/docs/features/slash-commands.html">斜杠命令</a>。</p><hr><h2 id="市场" tabindex="-1">市场 <a class="header-anchor" href="#市场" aria-label="Permalink to &quot;市场&quot;">​</a></h2><p><strong>市场</strong> 标签页管理插件来源，即从哪些仓库拉取可安装的插件列表。</p><h3 id="添加市场" tabindex="-1">添加市场 <a class="header-anchor" href="#添加市场" aria-label="Permalink to &quot;添加市场&quot;">​</a></h3><p>在顶部输入框填写市场来源后点击 <strong>添加市场</strong>：</p><ul><li><strong>Claude 模式</strong> 示例：<code>anthropics/claude-plugins-official</code>、<code>https://github.com/org/repo.git</code>、<code>/path/to/local-marketplace</code></li><li><strong>Codex 模式</strong> 示例：<code>openai/plugins</code></li></ul><h3 id="市场列表" tabindex="-1">市场列表 <a class="header-anchor" href="#市场列表" aria-label="Permalink to &quot;市场列表&quot;">​</a></h3><p>每条市场记录显示名称、可用插件数量及最近更新时间。</p><p>每行右侧提供以下操作（按条件显示）：</p><ul><li><strong>刷新快照按钮</strong>（刷新图标）— 仅 Codex 模式下的 Git 类型市场显示，用于拉取该市场仓库的最新提交</li><li><strong>删除按钮</strong>（垃圾桶图标）— 从列表中移除该市场；移除后该市场提供的插件从 <strong>发现</strong> 标签页消失，已安装的插件不受影响</li></ul><hr><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><p>若插件列表加载失败（提示未找到 Claude CLI 或 Codex CLI），请先在 <a href="/docs/settings/general.html">常规设置</a> 中配置正确的 CLI 路径，然后点击弹出提示中的 <strong>打开常规设置</strong> 跳转。</p><p>插件安装或状态变更后，运行中的对话会话将在 <strong>下次发送消息时</strong> 生效，无需重启应用。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/settings/skills.html">技能</a> — 管理预置的专项工作流，与插件命令一同出现在 <code>/</code> 面板中</li><li><a href="/docs/settings/bots.html">机器人渠道</a> — 把微信或飞书接入 LoongCode，远程驱动任务</li></ul>',37)])])}const m=o(n,[["render",l]]);export{u as __pageData,m as default};
